-- Modify "organization_metadata" table
ALTER TABLE "organization_metadata" ADD COLUMN "svix_app_id" text NULL;
-- Create "outbox" table
CREATE TABLE "outbox" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "public_id" uuid NOT NULL DEFAULT generate_uuidv7(),
  "organization_id" text NOT NULL,
  "event_type" text NOT NULL,
  "payload" jsonb NOT NULL,
  "created_at" timestamptz NOT NULL DEFAULT clock_timestamp(),
  PRIMARY KEY ("id"),
  CONSTRAINT "outbox_organization_id_fkey" FOREIGN KEY ("organization_id") REFERENCES "organization_metadata" ("id") ON UPDATE NO ACTION ON DELETE CASCADE
);
-- Create index "outbox_organization_id_id_idx" to table: "outbox"
CREATE INDEX "outbox_organization_id_id_idx" ON "outbox" ("organization_id", "id");
-- Create "outbox_svix_relays" table
CREATE TABLE "outbox_svix_relays" (
  "outbox_id" bigint NOT NULL,
  "processed_at" timestamptz NULL,
  "noop" boolean NOT NULL DEFAULT false,
  "dead_lettered" boolean NOT NULL DEFAULT false,
  "svix_message_id" text NULL,
  "attempts" integer NOT NULL DEFAULT 0,
  "last_error" text NULL,
  "created_at" timestamptz NOT NULL DEFAULT clock_timestamp(),
  "updated_at" timestamptz NOT NULL DEFAULT clock_timestamp(),
  PRIMARY KEY ("outbox_id"),
  CONSTRAINT "outbox_svix_relays_outbox_id_fkey" FOREIGN KEY ("outbox_id") REFERENCES "outbox" ("id") ON UPDATE NO ACTION ON DELETE CASCADE
) WITH (fillfactor = 80, autovacuum_vacuum_scale_factor = 0.05, autovacuum_analyze_scale_factor = 0.05);
-- Create index "outbox_svix_relays_pending_idx" to table: "outbox_svix_relays"
CREATE INDEX "outbox_svix_relays_pending_idx" ON "outbox_svix_relays" ("outbox_id") WHERE ((processed_at IS NULL) AND (dead_lettered IS FALSE));
